import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secret.txt";
        String directory = "/var/www/files/";

        File baseDirectory = new File(directory);
        File requestedFile = new File(baseDirectory, userInput).getCanonicalFile();

        if (!requestedFile.toPath().startsWith(baseDirectory.toPath())) {
            System.out.println("Access to files outside the base directory is not allowed.");
            return;
        }

        try (FileInputStream fis = new FileInputStream(requestedFile)) {
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

